 fn json_string_field(line: &str, field: &str) -> Option<String> {
     let needle = format!(r#""{field}":"#);
     let start = line.find(&needle)? + needle.len();
     let mut chars = line[start..].chars();
     if chars.next()? != '"' {
         return None;
     }

     let mut value = String::new();
     let mut escaped = false;
     for ch in chars {
         if escaped {
             match ch {
                 '"' => value.push('"'),
                 '\\' => value.push('\\'),
                 '/' => value.push('/'),
                 'b' => value.push('\u{0008}'),
                 'f' => value.push('\u{000c}'),
                 'n' => value.push('\n'),
                 'r' => value.push('\r'),
                 't' => value.push('\t'),
                 other => value.push(other),
             }
             escaped = false;
         } else if ch == '\\' {
             escaped = true;
         } else if ch == '"' {
             return Some(value);
         } else {
             value.push(ch);
         }
     }
     None
 }

